import java.util.function.*;

// Pattern 1: Method reference of a specific instance
String greeting = "Hello";
Supplier<String> s1 = () -> greeting.toUpperCase();  // Lambda expression
Supplier<String> s2 = greeting::toUpperCase;          // Method reference
