public class CaptureExample {
    public static void main(String[] args) {
        String name = "Java"; // effectively final (no reassignment)
        int count = 3;        // effectively final

        // OK: referencing effectively final variables
        Runnable r1 = () -> {
            System.out.println(name + " x " + count);
        };
        r1.run(); // Java x 3

        int num = 10;
        num = 20; // reassignment → no longer effectively final

        // Compilation error! num is not effectively final
        // Runnable r2 = () -> System.out.println(num);
    }
}

public class CaptureRules {
    int instanceVar = 100; // Instance variable
    static int staticVar = 200; // Static variable

    void demo() {
        final int a = 1;     // final → OK
        int b = 2;          // effectively final → OK
        int c = 3;
        c = 4;              // reassignment → NG

        Runnable r = () -> {
            System.out.println(a);           // OK
            System.out.println(b);           // OK
            // System.out.println(c);        // Compilation error
            System.out.println(instanceVar); // OK (instance variable)
            System.out.println(staticVar);   // OK (static variable)
            instanceVar = 999;               // OK (instance variables can be modified)
        };
    }
}

public class ShadowingExample {
    public static void main(String[] args) {
        int x = 10;

        // Lambda expression: shadowing not allowed
        // Consumer<Integer> c = (x) -> {};  // Compilation error!
        // x is already declared in the outer scope

        // Anonymous class: shadowing OK (separate scope)
        Runnable r = new Runnable() {
            @Override
            public void run() {
                int x = 20; // OK (anonymous class has a separate scope)
                System.out.println(x); // 20
            }
        };
    }
}

// Variable capture in for loops
List<Runnable> tasks = new ArrayList<>();
for (int i = 0; i < 3; i++) {
    int num = i; // New variable per iteration (effectively final)
    tasks.add(() -> System.out.println(num)); // OK
    // tasks.add(() -> System.out.println(i)); // Compilation error! i is reassigned
}
tasks.forEach(Runnable::run); // 0, 1, 2

